let trendsChartInstance = null;
let brandChartInstance = null;
let categoryChartInstance = null;
function triggerRefresh() {
  appsmith.trigger("get_dashboard_data.run()");
}
function updateUI() {
  const modelData = appsmith.model || {};
  const summary = modelData.summary || {};
  const dsePerf = modelData.dse_performance || [];
  const hourlyTrends = modelData.hourly_trends || [];
  const recentOrders = modelData.recent_orders || [];
  const topBrands = modelData.top_brands || [];
  const topCategories = modelData.top_categories || [];

  // Update Timestamp
  const lastUpdatedEl = document.getElementById("last-updated");
  if (lastUpdatedEl) {
    const now = new Date();
    lastUpdatedEl.innerText = `Last updated: ${now.toLocaleTimeString()}`;
  }

  // Render KPI Summary Cards
  const summaryContainer = document.getElementById("summary-cards");
  if (summaryContainer) {
    const totalReg = summary.total_registered !== undefined ? summary.total_registered : summary.total_registeres !== undefined ? summary.total_registeres : 0;
    const totalCheckIn = summary.total_checked_in || 0;
    const arrivalRate = totalReg > 0 ? Math.round(totalCheckIn / totalReg * 100) : 0;
    const completed = summary.completed || 0;
    const giftsCollected = summary.gifts_collected || 0;
    const giftRate = completed > 0 ? Math.round(giftsCollected / completed * 100) : 0;
    summaryContainer.innerHTML = `
      <div class="kpi-card registered">
        <div class="kpi-label">Registered</div>
        <div class="kpi-value">${totalReg}</div>
        <div class="kpi-subtext">Total expected list</div>
      </div>
      <div class="kpi-card checked-in">
        <div class="kpi-label">Checked-In</div>
        <div class="kpi-value">${totalCheckIn}</div>
        <div class="kpi-subtext">Arrival rate: ${arrivalRate}%</div>
      </div>
      <div class="kpi-card queue">
        <div class="kpi-label">In Queue</div>
        <div class="kpi-value">${summary.arrived || 0}</div>
        <div class="kpi-subtext">Waiting for assignment</div>
      </div>
      <div class="kpi-card engaged">
        <div class="kpi-label">Ordering</div>
        <div class="kpi-value">${summary.engaged || 0}</div>
        <div class="kpi-subtext">Active guide punchings</div>
      </div>
      <div class="kpi-card ready">
        <div class="kpi-label">Ready Checkout</div>
        <div class="kpi-value">${summary.ready_for_checkout || 0}</div>
        <div class="kpi-subtext">Order synced at desk</div>
      </div>
      <div class="kpi-card completed">
        <div class="kpi-label">Completed</div>
        <div class="kpi-value">${completed}</div>
        <div class="kpi-subtext">Gifts collected: ${giftsCollected} (${giftRate}%)</div>
      </div>
      <div class="kpi-card revenue">
        <div class="kpi-label">Total Value</div>
        <div class="kpi-value">Rs. ${(summary.total_order_value || 0).toLocaleString('en-IN', {
      maximumFractionDigits: 0
    })}</div>
        <div class="kpi-subtext">Across all punched orders</div>
      </div>
      <div class="kpi-card duration">
        <div class="kpi-label">Avg Duration</div>
        <div class="kpi-value">${summary.avg_duration_mins || 0} Mins</div>
        <div class="kpi-subtext">Average checkout time</div>
      </div>
    `;
  }

  // Render DSE Leaderboard Table
  const dseBody = document.getElementById("dse-leaderboard-body");
  if (dseBody) {
    dseBody.innerHTML = dsePerf.map(dse => `
      <tr>
        <td><strong>${dse.employee_name}</strong></td>
        <td><code>${dse.employee_code}</code></td>
        <td>${dse.assigned_count} customers</td>
        <td>${dse.completed_count} checked out</td>
        <td class="text-right"><strong>Rs. ${dse.total_order_value.toLocaleString('en-IN', {
      maximumFractionDigits: 0
    })}</strong></td>
      </tr>
    `).join("");
    if (dsePerf.length === 0) {
      dseBody.innerHTML = `<tr><td colspan="5" style="text-align:center;color:var(--text-secondary)">No active guides mapped yet</td></tr>`;
    }
  }

  // Render Recent Orders Table
  const orderBody = document.getElementById("recent-orders-body");
  if (orderBody) {
    orderBody.innerHTML = recentOrders.map(order => `
      <tr>
        <td><code>#ORD-${order.order_id}</code></td>
        <td><strong>${order.customer_name}</strong></td>
        <td><code>${order.customer_code}</code></td>
        <td>${order.assigned_employee || "-"}</td>
        <td>${new Date(order.synced_at).toLocaleTimeString([], {
      hour: '2-digit',
      minute: '2-digit'
    })}</td>
        <td class="text-right"><strong>Rs. ${order.total_amount.toLocaleString('en-IN', {
      maximumFractionDigits: 0
    })}</strong></td>
      </tr>
    `).join("");
    if (recentOrders.length === 0) {
      orderBody.innerHTML = `<tr><td colspan="6" style="text-align:center;color:var(--text-secondary)">No orders submitted yet</td></tr>`;
    }
  }

  // Render ChartJS Visualisations (Check if Chart library is loaded synchronously)
  if (typeof Chart !== "undefined") {
    renderTrendsChart(hourlyTrends);
    renderBrandChart(topBrands);
    renderCategoryChart(topCategories);
  }
}

// 1. Hourly flow chart
function renderTrendsChart(data) {
  const canvas = document.getElementById('trendsChart');
  if (!canvas) return;
  const labels = data.map(item => item.hour_label);
  const checkins = data.map(item => item.checkins_count);
  const revenue = data.map(item => item.order_value / 1000); // in thousands

  if (trendsChartInstance) trendsChartInstance.destroy();
  trendsChartInstance = new Chart(canvas.getContext('2d'), {
    type: 'bar',
    data: {
      labels: labels,
      datasets: [{
        label: 'Check-ins',
        data: checkins,
        backgroundColor: 'rgba(59, 130, 246, 0.65)',
        borderColor: 'rgb(59, 130, 246)',
        borderWidth: 1,
        yAxisID: 'yCheckins'
      }, {
        label: 'Value (k)',
        type: 'line',
        data: revenue,
        borderColor: 'rgb(236, 72, 153)',
        backgroundColor: 'rgba(236, 72, 153, 0.1)',
        borderWidth: 2,
        tension: 0.3,
        yAxisID: 'yRevenue'
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      scales: {
        x: {
          grid: {
            display: false
          },
          ticks: {
            font: {
              size: 8
            }
          }
        },
        yCheckins: {
          type: 'linear',
          position: 'left',
          grid: {
            display: false
          },
          ticks: {
            font: {
              size: 8
            }
          }
        },
        yRevenue: {
          type: 'linear',
          position: 'right',
          grid: {
            color: '#f1f5f9'
          },
          ticks: {
            font: {
              size: 8
            }
          }
        }
      }
    }
  });
}

// 2. Brand Share Doughnut Chart
function renderBrandChart(data) {
  const canvas = document.getElementById('brandChart');
  if (!canvas) return;
  const labels = data.map(item => item.brand_name);
  const values = data.map(item => item.total_value);
  if (brandChartInstance) brandChartInstance.destroy();
  brandChartInstance = new Chart(canvas.getContext('2d'), {
    type: 'doughnut',
    data: {
      labels: labels,
      datasets: [{
        data: values,
        backgroundColor: ['#3b82f6', '#10b981', '#ec4899', '#f59e0b', '#8b5cf6'],
        borderWidth: 1
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: {
          position: 'right',
          labels: {
            boxWidth: 10,
            font: {
              size: 9
            }
          }
        }
      }
    }
  });
}

// 3. Category Horizontal Bar Chart
function renderCategoryChart(data) {
  const canvas = document.getElementById('categoryChart');
  if (!canvas) return;
  const labels = data.map(item => item.category_name);
  const values = data.map(item => item.total_value / 1000); // in thousands

  if (categoryChartInstance) categoryChartInstance.destroy();
  categoryChartInstance = new Chart(canvas.getContext('2d'), {
    type: 'bar',
    data: {
      labels: labels,
      datasets: [{
        label: 'Order Value (k)',
        data: values,
        backgroundColor: 'rgba(6, 182, 212, 0.7)',
        borderColor: 'rgb(6, 182, 212)',
        borderWidth: 1
      }]
    },
    options: {
      indexAxis: 'y',
      responsive: true,
      maintainAspectRatio: false,
      scales: {
        x: {
          ticks: {
            font: {
              size: 8
            }
          }
        },
        y: {
          ticks: {
            font: {
              size: 8
            }
          },
          grid: {
            display: false
          }
        }
      }
    }
  });
}

// React to appsmith model updates
appsmith.onModelChange(updateUI);

// Trigger initial rendering on widget load
updateUI();

