function updateUI() {
  const model = appsmith.model || {};
  const items = model.items || [];
  let grandTotal = 0;
  let totalQty = 0;
  let totalTaxable = 0;
  let totalTax = 0;
  const taxSummaryMap = {};
  items.forEach(row => {
    const qty = Number(row.quantity || 0);
    const rate = Number(row.rate || 0);
    const net = Number(row.amount || 0);
    const gst_pct = Number(row.gst_rate || 0);

    // Inclusive GST math matching the PDF
    const taxable = net / (1 + gst_pct / 100);
    const gst_amt = net - taxable;
    grandTotal += net;
    totalQty += qty;
    totalTaxable += taxable;
    totalTax += gst_amt;
    if (!taxSummaryMap[gst_pct]) {
      taxSummaryMap[gst_pct] = {
        gst_rate: gst_pct,
        taxable: 0,
        gst_amt: 0
      };
    }
    taxSummaryMap[gst_pct].taxable += taxable;
    taxSummaryMap[gst_pct].gst_amt += gst_amt;
  });

  // 1. Render Metrics Values
  const grandTotalEl = document.getElementById("grand-total");
  if (grandTotalEl) {
    grandTotalEl.innerText = `Rs. ${grandTotal.toLocaleString('en-IN', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    })}`;
  }
  const totalQtyEl = document.getElementById("total-qty");
  if (totalQtyEl) {
    totalQtyEl.innerText = `${totalQty} Pcs`;
  }
  const taxableValueEl = document.getElementById("taxable-value");
  if (taxableValueEl) {
    taxableValueEl.innerText = `Rs. ${totalTaxable.toLocaleString('en-IN', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    })}`;
  }
  const taxValueEl = document.getElementById("tax-value");
  if (taxValueEl) {
    taxValueEl.innerText = `Rs. ${totalTax.toLocaleString('en-IN', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    })}`;
  }

  // 2. Render GST Slabs Table rows
  const tableBody = document.getElementById("tax-breakdown-body");
  if (tableBody) {
    const sortedSummary = Object.values(taxSummaryMap).sort((a, b) => b.gst_rate - a.gst_rate);
    tableBody.innerHTML = sortedSummary.map(s => {
      const halfRate = (s.gst_rate / 2).toFixed(1) + "%";
      const halfAmt = (s.gst_amt / 2).toFixed(2);
      return `
        <tr>
          <td><strong>${s.gst_rate.toFixed(1)}%</strong></td>
          <td class="text-right">Rs. ${s.taxable.toLocaleString('en-IN', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
      })}</td>
          <td class="text-right"><code>${halfRate}</code></td>
          <td class="text-right">Rs. ${parseFloat(halfAmt).toLocaleString('en-IN', {
        minimumFractionDigits: 2
      })}</td>
          <td class="text-right"><code>${halfRate}</code></td>
          <td class="text-right">Rs. ${parseFloat(halfAmt).toLocaleString('en-IN', {
        minimumFractionDigits: 2
      })}</td>
          <td class="text-right"><strong>Rs. ${s.gst_amt.toLocaleString('en-IN', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
      })}</strong></td>
        </tr>
      `;
    }).join("");
    if (sortedSummary.length === 0) {
      tableBody.innerHTML = `<tr><td colspan="7" style="text-align:center;color:var(--text-secondary)">No items mapped in this order</td></tr>`;
    }
  }
}

// React to appsmith model updates
appsmith.onModelChange(updateUI);

// Trigger initial rendering on widget load
updateUI();

