:root {
  --bg-card: #ffffff;
  --text-primary: #0f172a;
  --text-secondary: #64748b;
  --border-color: #cbd5e1;
  --primary: #3b82f6;
  --success: #10b981;
  --accent: #ec4899;
}

body {
  font-family: "Inter", -apple-system, sans-serif;
  margin: 0;
  padding: 8px;
  background-color: transparent;
  color: var(--text-primary);
  box-sizing: border-box;
}

.summary-wrapper {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.panel-header h3 {
  font-size: 13px;
  font-weight: 600;
  margin: 0;
  border-left: 3px solid var(--primary);
  padding-left: 8px;
}

/* Metrics Cards */
.metrics-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

@media (max-width: 600px) {
  .metrics-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}
.metric-card {
  background: var(--bg-card);
  border: 1px solid #e2e8f0;
  border-radius: 6px;
  padding: 8px 10px;
  display: flex;
  flex-direction: column;
  position: relative;
}

.metric-card::before {
  content: "";
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  width: 3px;
  border-radius: 6px 0 0 6px;
}

.metric-card.value-card::before {
  background: var(--success);
}

.metric-card.qty-card::before {
  background: var(--primary);
}

.metric-card.taxable-card::before {
  background: var(--text-secondary);
}

.metric-card.tax-card::before {
  background: var(--accent);
}

.metric-card .label {
  font-size: 9px;
  text-transform: uppercase;
  font-weight: 600;
  color: var(--text-secondary);
}

.metric-card .value {
  font-size: 14px;
  font-weight: 700;
  margin-top: 4px;
}

/* Table Style */
.table-card {
  background: var(--bg-card);
  border: 1px solid #e2e8f0;
  border-radius: 6px;
  overflow: hidden;
}

.table-wrapper {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 10.5px;
}

th {
  background: #f8fafc;
  color: var(--text-secondary);
  font-weight: 600;
  text-align: left;
  padding: 6px 8px;
  border-bottom: 1px solid #e2e8f0;
}

td {
  padding: 6px 8px;
  border-bottom: 1px solid #f1f5f9;
}

tr:hover td {
  background: #f8fafc;
}

.text-right {
  text-align: right;
}

code {
  font-family: monospace;
  background: #f1f5f9;
  padding: 1px 4px;
  border-radius: 3px;
}

