async function () {
  try {
    await get_meet_settings.run();
    await get_order_details.run();
    const brand = get_meet_settings.data || ({});
    const order = get_order_details.data || ({});
    const items = order.items || [];
    const grandTotal = Number(order.total_amount || 0);
    if (!order.checkin_id) {
      throw new Error("No check-in or order data found for the selected customer.");
    }
    if (typeof jspdf === "undefined") {
      throw new Error("jsPDF library not loaded. Please install it in Appsmith Settings -> Libraries.");
    }
    const jsPDFConstructor = jspdf.jsPDF || jspdf;
    const doc = new jsPDFConstructor('p', 'pt', 'a4');
    if (typeof doc.autoTable !== "function" && jspdf.plugin && jspdf.plugin.autotable) {
      jsPDFConstructor.API.autoTable = jspdf.plugin.autotable;
    }
    const margin = 12;
    const pageWidth = doc.internal.pageSize.width;
    const pageHeight = doc.internal.pageSize.height;
    const toWords = num => {
      const a = ['', 'One ', 'Two ', 'Three ', 'Four ', 'Five ', 'Six ', 'Seven ', 'Eight ', 'Nine ', 'Ten ', 'Eleven ', 'Twelve ', 'Thirteen ', 'Fourteen ', 'Fifteen ', 'Sixteen ', 'Seventeen ', 'Eighteen ', 'Nineteen '];
      const b = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];
      const n = ("000000000" + Math.floor(num)).substr(-9).match(/^(\d{2})(\d{2})(\d{2})(\d{1})(\d{2})$/);
      if (!n) return '';
      let str = '';
      str += Number(n[1]) != 0 ? (a[Number(n[1])] || b[n[1][0]] + ' ' + a[n[1][1]]) + 'Crore ' : '';
      str += Number(n[2]) != 0 ? (a[Number(n[2])] || b[n[2][0]] + ' ' + a[n[2][1]]) + 'Lakh ' : '';
      str += Number(n[3]) != 0 ? (a[Number(n[3])] || b[n[3][0]] + ' ' + a[n[3][1]]) + 'Thousand ' : '';
      str += Number(n[4]) != 0 ? (a[Number(n[4])] || b[n[4][0]] + ' ' + a[n[4][1]]) + 'Hundred ' : '';
      str += Number(n[5]) != 0 ? (str != '' ? 'and ' : '') + (a[Number(n[5])] || b[n[5][0]] + ' ' + a[n[5][1]]) + 'Only ' : 'Only ';
      return str;
    };
    const drawHeader = (currentPage, totalPages) => {
      const headerY = margin;
      if (brand.logo_url && brand.logo_url.startsWith("data:image/")) {
        try {
          doc.addImage(brand.logo_url, 'PNG', margin, headerY, 90, 25);
        } catch (e) {}
      } else {
        doc.setTextColor(0, 0, 0);
        doc.setFont("helvetica", "bold");
        doc.setFontSize(14);
        doc.text(String(brand.company_name || "ZENITH"), margin, headerY + 15);
      }
      doc.setTextColor(0, 0, 0);
      doc.setFont("helvetica", "bold");
      doc.setFontSize(14);
      doc.text("EVENT BOOKING ORDER", pageWidth / 2, headerY + 15, {
        align: "center"
      });
      doc.setFontSize(8.5);
      doc.setFont("helvetica", "normal");
      doc.text(`Order Ref: #MEET-${order.order_id || "PENDING"}`, pageWidth - margin, headerY + 10, {
        align: "right"
