        doc.text(`Date: ${order.completed_at ? moment(order.completed_at).format("DD/MM/YYYY HH:mm") : moment().format("DD/MM/YYYY")}`, pageWidth - margin, headerY + 22, { align: "right" });

        // 3-Column Meta Boxes
        const boxesY = headerY + 32;
        const gap = 6;
        const boxWidth = (pageWidth - (margin * 2) - (gap * 2)) / 3;
        const boxHeight = 95;

        // Box 1: Organization details (From settings table)
        this._drawSimpleBox(doc, margin, boxesY, boxWidth, boxHeight, [
          ["From", String(brand.company_name)],
          ["Address", String(brand.address)],
          ["City/PIN", `${brand.district || ""} - ${brand.pin || ""}`],
          ["GSTIN", String(brand.gstin || "-")],
          ["Email", String(brand.email || "-")],
          ["Phone", String(brand.contact_no || "-")]
        ], 50);

        // Box 2: Customer / Visitor details (Compact layout - removed badge/vehicle)
        const customerAddress = [
          order.address_line1,
          order.address_line2,
          order.city,
          order.state,
          order.pincode
        ].filter(Boolean).join(", ");

        this._drawSimpleBox(doc, margin + boxWidth + gap, boxesY, boxWidth, boxHeight, [
          ["Customer", String(order.customer_name)],
          ["Code", String(order.customer_code || "-")],
          ["Address", customerAddress || "-"],
          ["Visitor", String(order.visitor_name || "-")],
          ["Contact", String(order.contact_number || "-")],
          ["No. People", String(order.no_of_people || "1")]
        ], 60);

        // Box 3: Event Visit Metrics & Salesperson Info
        this._drawSimpleBox(doc, margin + (boxWidth * 2) + (gap * 2), boxesY, boxWidth, boxHeight, [
          ["Default DSE", String(order.default_employee || "-")],
          ["Event Guide", String(order.assigned_employee || "-")],
          ["Route/Area", String(order.route || "-")],
          ["Check-In", order.checked_in_at ? moment(order.checked_in_at).format("HH:mm") : "-"],
          ["Assigned", order.assigned_at ? moment(order.assigned_at).format("HH:mm") : "-"],
          ["Completed", order.completed_at ? moment(order.completed_at).format("HH:mm") : "-"],
          ["Page", `${currentPage} of ${totalPages}`]
        ], 68);

        return boxesY + boxHeight;
      };

      // 3. Render Item Lines Table with Expanded Columns
      doc.autoTable({
        startY: margin + 32 + 95 + 10,
        margin: { left: margin, right: margin, top: 149, bottom: 20 },
        head: [["S.N", "ITEM DESCRIPTION", "BRAND", "CATEGORY", "MRP", "QTY", "RATE", "GROSS", "SCH", "TAXABLE", "GST%", "GST AMT", "NET"]],
        body: items.map((row, index) => {
          const gst_pct = Number(row.gst_rate || 0);
          const net = Number(row.amount || 0);
          const qty = Number(row.quantity || 0);
          const rate = Number(row.rate || 0);
          const mrp = Number(row.mrp || 0);

          // Inclusive GST math:
          const taxable = net / (1 + (gst_pct / 100));
          const gst_amt = net - taxable;
          const gross = taxable;
          const scheme = 0.00; // default scheme log

          return [
            index + 1,
            row.product_name,
            row.brand_name || "-",
            row.category_name || "-",
            mrp.toFixed(2),
