          0: { cellWidth: 20, halign: 'center' },
          1: { cellWidth: 'auto', minCellWidth: 100 },
          2: { cellWidth: 45 },
          3: { cellWidth: 45 },
          4: { halign: 'right', cellWidth: 35 },
          5: { halign: 'center', cellWidth: 25 },
          6: { halign: 'right', cellWidth: 35 },
          7: { halign: 'right', cellWidth: 40 },
          8: { halign: 'right', cellWidth: 30 },
          9: { halign: 'right', cellWidth: 40 },
          10: { halign: 'center', cellWidth: 30 },
          11: { halign: 'right', cellWidth: 38 },
          12: { halign: 'right', cellWidth: 45 }
        }
      });

      // --- 4. CALCULATE AND RENDER TAX SUMMARY ---
      const taxSummaryMap = {};
      items.forEach(row => {
        const gst_pct = Number(row.gst_rate || 0);
        const net = Number(row.amount || 0);
        const taxable = net / (1 + (gst_pct / 100));
        const gst_amt = net - taxable;

        if (!taxSummaryMap[gst_pct]) {
          taxSummaryMap[gst_pct] = {
            gst_rate: gst_pct,
            taxable: 0,
            gst_amt: 0
          };
        }
        taxSummaryMap[gst_pct].taxable += taxable;
        taxSummaryMap[gst_pct].gst_amt += gst_amt;
      });

      const taxSummaryRows = Object.values(taxSummaryMap).map(summary => {
        const halfRate = (summary.gst_rate / 2).toFixed(1) + "%";
        const halfAmt = (summary.gst_amt / 2).toFixed(2);
        return [
          summary.gst_rate.toFixed(1) + "%",
          summary.taxable.toFixed(2),
          halfRate,
          halfAmt,
          halfRate,
          halfAmt,
          summary.gst_amt.toFixed(2)
        ];
