        startY: doc.lastAutoTable.finalY + 10,
        margin: { left: margin, right: margin },
        head: [["GST RATE", "TAXABLE VALUE", "CGST RATE", "CGST AMT", "SGST RATE", "SGST AMT", "TOTAL TAX"]],
        body: taxSummaryRows,
        theme: 'grid',
        styles: { fontSize: 7.5, cellPadding: 3, lineColor: [0, 0, 0], lineWidth: 0.5, textColor: [0, 0, 0] },
        headStyles: { fillColor: [240, 240, 240], textColor: [0, 0, 0], fontStyle: 'bold', lineWidth: 0.5, halign: 'center' },
        columnStyles: {
          0: { halign: 'center' },
          1: { halign: 'right' },
          2: { halign: 'center' },
          3: { halign: 'right' },
          4: { halign: 'center' },
          5: { halign: 'right' },
          6: { halign: 'right' }
        }
      });

      // 5. Footer Calculations & Layout Check
      let currentY = doc.lastAutoTable.finalY + 15;
      const footerHeight = 150;

      if (currentY + footerHeight > pageHeight) {
        doc.addPage();
        drawHeader(doc.internal.getNumberOfPages(), doc.internal.getNumberOfPages());
        currentY = 149;
      }

      // Order Totals Summary (Clean black & white)
      doc.setFontSize(9);
      doc.setFont("helvetica", "bold");
      doc.text(`Total Punched Items: ${items.reduce((sum, item) => sum + Number(item.quantity || 0), 0)} Pcs`, margin, currentY);
      doc.text(`Grand Total Order Value: Rs. ${Number(grandTotal).toFixed(2)}`, margin, currentY + 12);

      doc.text("Total Amount (in words):", margin, currentY + 24);
      doc.setFont("helvetica", "normal");
      doc.text(toWords(Math.round(grandTotal)), margin + 115, currentY + 24);

      // Signatures Box
      const sigY = currentY + 45;
      doc.setDrawColor(0, 0, 0);
      doc.setLineWidth(0.5);
      doc.line(margin, sigY, pageWidth - margin, sigY);

      doc.setFontSize(9);
      doc.setFont("helvetica", "bold");
      doc.text("EVENT CHECKOUT SLIP", pageWidth / 2, sigY + 12, { align: "center" });

      doc.setFontSize(8);
      doc.setFont("helvetica", "normal");
      doc.text("This is an official record of event booking compiled during the Dealers Meet.", margin, sigY + 28);
      doc.text("Receiver Signature: _______________________", margin, sigY + 55);
      doc.text("Authorized Executive Signature: _______________________", pageWidth / 2 + 5, sigY + 55);

      // Save PDF and Trigger Download
      const fileName = `Order_${order.customer_code || "Customer"}_${order.checkin_id}.pdf`;
      download(doc.output('dataurlstring'), fileName, "application/pdf");
      showAlert("Order Invoice PDF generated successfully!", "success");

    } catch (err) {
      showAlert("PDF Generation Error: " + err.message, "error");
    }
  },

  // Helper function to draw structured borders/boxes
  _drawSimpleBox(doc, x, y, width, height, rows, labelWidth = 58) {
    doc.setDrawColor(0, 0, 0);
    doc.setLineWidth(0.5);
    doc.rect(x, y, width, height);

    let rowY = y + 12;
    rows.forEach(r => {
      doc.setFontSize(8);
      doc.setFont("helvetica", "bold");
      doc.setTextColor(0, 0, 0);
      const label = String(r[0]) + ":";
      doc.text(label, x + 5, rowY);

      doc.setFont("helvetica", "normal");
      const val = String(r[1] || "-");
      const splitVal = doc.splitTextToSize(val, width - labelWidth - 5);
      doc.text(splitVal, x + labelWidth, rowY);
      rowY += (splitVal.length * 9) + 1.2;
    });
  }
}

